import { AsyncStorage } from 'react-native';

// 1. Create class (static class, not instance) named CacheManager with following public properties and methods:

export default class CacheManager {
    static getSettings(key){ // 2
        return AsyncStorage.getItem(key);
    }

    static setSettings(key, value){ 
        console.log('Saving ' + key + ':');
        try{
            console.log('before set: ' + JSON.stringify(key));

            let oldData = AsyncStorage.getItem(key)
            if (oldData != null){
                oldData = JSON.parse(oldData);
            } else {
                oldData = {}; 
            }
            oldData[key] = value;
            
            console.log('old data: ' + JSON.stringify(oldData));

            // save new data
            AsyncStorage.setItem(key, JSON.stringify(oldData)); 

            return true 
        } catch (e){
            return false
        };
    }
}